3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const SWORD_BASE_PREMIUM = 100;
23	
24	export function quote(input: QuoteInput): number {
25	  if (input.items.length === 0) return PROCESSING_FEE;
26	  const policyBase = SWORD_BASE_PREMIUM;
27	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
28	  return policyBase + firstInsuranceSurcharge + PROCESSING_FEE;
29	}
